UPDATE CREDIT_CARD_APPLICATIONS
SET    id_verified_yn    = #{idVerifiedYn}
WHERE  credit_app_id     = #{creditAppId}

UPDATE CREDIT_CARD_APPLICATIONS
SET    applicant_snapshot  = #{applicantSnapshot, typeHandler=aesTypeHandler},
       annual_income_band  = #{annualIncomeBand},
       credit_score_band   = #{creditScoreBand},
       linked_account_id   = #{linkedAccountId, jdbcType=NUMERIC}
WHERE  credit_app_id       = #{creditAppId}

UPDATE CREDIT_CARD_APPLICATIONS
SET    income_doc_key  = #{incomeDocKey},
       asset_doc_key   = #{assetDocKey,  jdbcType=VARCHAR},
       job_doc_key     = #{jobDocKey}
WHERE  credit_app_id   = #{creditAppId}

